-- descriptions and helps
ZO_CreateStringId("MSAL_HELP_TITLE","|c999999AutoLoot+ ist ein Loot-Manager basierend auf |ceeeeeeEigenen Regeln|c999999. Definiere, was in deinen Beutel gehört, und lass das Addon den Rest mit integrierten |ceeeeeeEntsorgern|c999999 erledigen. Zurücklassen, als Trödel markieren, zerlegen, zerstören — alles unter deiner Kontrolle|r")
ZO_CreateStringId("MSAL_HELP_GEAR","|c999999Für |ceeeeeegesammelte Set-Items|c999999, die vom Set-Items-Filter aussortiert wurden, verwendet das Addon die nachfolgenden Filter in <<1>>, um zu bestimmen, ob sie geplündert werden sollen.|r")
ZO_CreateStringId("MSAL_HELP_MATERIAL","|c999999Materialien werden automatisch geplündert, wenn du |ceeeeee" .. GetString(SI_CROWN_STORE_MENU_ESO_PLUS_LABEL) .. "|c999999 besitzt, unabhängig von den Filtereinstellungen, es sei denn, sie wurden gestohlen.|r")
ZO_CreateStringId("MSAL_HELP_MISC","|c999999Für einige hochwertige Handelsgegenstände unterstützt das Add-on den Preisvergleich über Drittanbieter-Add-ons (|ceeeeeeTTC, MM, ATT und TSC werden unterstützt|c999999). \nZugehörige Funktionen werden diesem Menü automatisch hinzugefügt, sobald Sie sie aktivieren.|r")
ZO_CreateStringId("MSAL_HELP_MISC_3RD_ENABLED","|c999999Bei einigen hochwertigen, handelbaren Gegenständen unterstützt das Add-on den Preisvergleich über Drittanbieter-Add-ons (unterstützt werden |ceeeeeeTTC, MM, ATT und TSC|c999999). \nWird eine Drittanbieterquelle ausgewählt, werden nicht handelbare Gegenstände oder solche ohne Preisdaten direkt geplündert.|r")
ZO_CreateStringId("MSAL_HELP_LIST","|c999999%s und %s bieten flexible Regelanpassung mit höchster Priorität. \nBlacklist für Items, die das Addon niemals auto-looten soll (z.B. Set-Gear zum Verkauf); Whitelist für Items, die immer aufgenommen werden sollen. \n\nLink einfügen und Enter drücken zum Hinzufügen; Dropdown-Menü zum Entfernen verwenden|r")
ZO_CreateStringId("MSAL_HELP_UNBOX","|c999999Öffnet Behälter automatisch beim Erhalten, mit |ceeeeee<<1>>|c999999 für herausgefilterte Items.\nSchaltflächen unten zum manuellen Öffnen aller Behälter. Tastenkombinationen (PC) und LibRadialMenu (Konsole) möglich.|r")
ZO_CreateStringId("MSAL_HELP_UNWANTED","|c999999Automatisches entsorgen unerwünschter Items nach festgelegten Filtern.|r")
ZO_CreateStringId("MSAL_HELP_UNWANTED_CONSOLE","|c999999Disposer performs auto action you set for filtered-out unwanted items. \n|ceeeeee<<1>>|c999999 feature is available here, with a matching |ceeeeeeAuto-Sell|c999999|r")
