ZO_CreateStringId("MSAL_HOST_LOOT_ALL","Originale <<1>> Schaltfläche überschreiben")
ZO_CreateStringId("MSAL_HOST_LOOT_ALL_TOOLTIP","Ermöglicht es dem Addon, die Originale Schaltfläche <<1>> zu überschreiben.\nWenn sie überschrieben wird, verhält sie sich identisch zum Original, mit der Ausnahme, dass sie Items auf der Blacklist überspringt und eine Benachrichtigung anzeigt, wenn ein Eintrag gefunden wird")
ZO_CreateStringId("MSAL_ATTACH_LOOT_BUTTON","Schaltfläche „<<1>>“ am Lootfenster")
