ZO_CreateStringId("MSAL_MEANWHILE_DESTROY_UNSELLABLE","Entsorge unverkäufliche Items.")
ZO_CreateStringId("MSAL_MEANWHILE_DESTROY_UNSELLABLE_TOOLTIP","Wenn diese Option aktiviert ist, werden unverkäufliche Items beim Klicken auf die Schaltfläche „Als Trödel markieren“ sofort entsorgt")
ZO_CreateStringId("MSAL_BLIST_TOOLTIP","Unabhängig davon, wie Du zwischen kontoweiten und rollenunabhängigen Einstellungen wechselst, bleibt die Blacklist bestehen, um mögliche unbeabsichtigte Folgen zu vermeiden")
ZO_CreateStringId("MSAL_PRINT_JUNK","Als Trödel markierte Items im Chat")
