ZO_CreateStringId("MSAL_STYLE_MATERIAL_3RD","<<1>> Preisschwelle")
ZO_CreateStringId("MSAL_STYLE_MATERIAL_3RD_TOOLTIP","Wenn die Einstellung |ccc922f<<1>>|r lautet, verwendet das Add-on weiterhin |ccc922f<<2>> -> <<3>>|r zum Filtern, ohne Preise von Drittanbietern zu berücksichtigen. \n\nWenn |ccc922f<<4>>|r eingestellt ist, verwendet das Add-on die folgenden Preise von Drittanbietern zum Filtern und überschreibt die Einstellungen |ccc922f<<2>> -> <<3>>|r")
ZO_CreateStringId("MSAL_STYLE_MATERIAL_3RD_GEAR_LOOTING","Ausrüstung im entsprechenden Stil plündern")
ZO_CreateStringId("MSAL_STYLE_MATERIAL_3RD_GEAR_LOOTING_TOOLTIP","Plündere außerdem diese wertvollen Stil-Ausrüstungsgegenstände, damit du sie zerlegen und Stilmaterialien erhalten kannst")
ZO_CreateStringId("MSAL_REGISTER_ABOVE_ITEM_FOR_DECON","Obige Gegenstände registrieren")
ZO_CreateStringId("MSAL_REGISTER_ABOVE_ITEM_FOR_DECON_TOOLTIP","Wenn aktiviert, werden über obige Option geplünderte Gegenstände beim nächsten Besuch einer Werkstation oder des Zerlegungs-Assistenten automatisch zum Zerlegen ausgewählt")
ZO_CreateStringId("MSAL_INTRICATE_DECON_TOOLTIP","Bei |ccc922f<<1>>|r werden geplünderte Gegenstände beim nächsten Werkstatt- oder Zerlegungs-Assistenten-Besuch automatisch ausgewählt\n\nNur aktiv, wenn die entsprechende |ccc922fHandwerkslinie noch NICHT Stufe 50 erreicht hat|r. Bei maximalen Skill-Linien werden sie nicht mehr registriert")
